#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

bool canPartition(int *nums, int n) {
    int sum = 0;
    for (int i = 0; i < n; ++i) sum += nums[i];
    if (sum % 2) return false;
    int target = sum / 2;
    bool *dp = (bool *)calloc(target + 1, sizeof(bool));
    dp[0] = true;
    for (int i = 0; i < n; ++i) {
        int v = nums[i];
        for (int j = target; j >= v; --j) {
            if (dp[j - v]) dp[j] = true;
        }
    }
    bool ans = dp[target];
    free(dp);
    return ans;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        int *arr = (int *)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        printf(canPartition(arr, N) ? "YES\n" : "NO\n");
        free(arr);
    }
    return 0;
}

