bool canPartition(const vector<int>& a) {
    int sum = accumulate(a.begin(), a.end(), 0);
    if (sum % 2) return false;
    int target = sum / 2;
    vector<char> dp(target + 1, 0);
    dp[0] = 1;
    for (int v : a) {
        for (int j = target; j >= v; --j) {
            if (dp[j - v]) dp[j] = 1;
        }
    }
    return dp[target];
}

