import sys

def can_partition(nums):
    total = sum(nums)
    if total & 1:
        return False
    target = total // 2
    dp = [False] * (target + 1)
    dp[0] = True
    for v in nums:
        for j in range(target, v - 1, -1):
            if dp[j - v]:
                dp[j] = True
    return dp[target]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it))
        arr = [int(next(it)) for _ in range(N)]
        out.append('YES' if can_partition(arr) else 'NO')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

